import{_ as t,o,c as a,an as r}from"./chunks/framework.CTqRDTHW.js";const h=JSON.parse('{"title":"Feature: Voice System","description":"","frontmatter":{},"headers":[],"relativePath":"016-voice-system/spec.md","filePath":"016-voice-system/spec.md","lastUpdated":1773141627000}'),d={name:"016-voice-system/spec.md"};function i(c,e,s,n,l,u){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="feature-voice-system" tabindex="-1">Feature: Voice System <a class="header-anchor" href="#feature-voice-system" aria-label="Permalink to &quot;Feature: Voice System&quot;">​</a></h1><blockquote><p><strong>Spec</strong>: 016-voice-system <strong>Author</strong>: arc-framework <strong>Date</strong>: 2026-03-06 <strong>Status</strong>: Draft <strong>ARD</strong>: <code>docs/ard/VOICE-SYSTEM.md</code><strong>HLD</strong>: <code>docs/ard/VOICE-HLD.md</code><strong>Framework</strong>: <code>docs/ard/ARC-ENTERPRISE-AI-FRAMEWORK.md</code></p></blockquote><h2 id="executive-summary" tabindex="-1">Executive Summary <a class="header-anchor" href="#executive-summary" aria-label="Permalink to &quot;Executive Summary&quot;">​</a></h2><p>Build <code>services/voice/</code> as ARC&#39;s production voice orchestration service. <code>arc-voice-agent</code> will expose OpenAI-compatible STT and TTS APIs, run a LiveKit worker for room-based audio-to-audio sessions, bridge voice turns into <code>arc-reasoner</code> instead of duplicating reasoning, and publish durable voice lifecycle events for analytics, billing, and compliance. Existing realtime infrastructure in <code>services/realtime/</code> becomes a dependency, not the feature itself.</p><h2 id="target-modules" tabindex="-1">Target Modules <a class="header-anchor" href="#target-modules" aria-label="Permalink to &quot;Target Modules&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>Path</th><th>Impact</th></tr></thead><tbody><tr><td>Services</td><td><code>services/voice/</code></td><td>New — <code>arc-voice-agent</code> production voice service</td></tr><tr><td>Services</td><td><code>services/profiles.yaml</code></td><td>Update — add <code>voice</code> to <code>reason</code> profile</td></tr><tr><td>Services</td><td><code>services/realtime/</code></td><td>Existing dependency — no new transport design</td></tr><tr><td>Contracts</td><td><code>services/voice/contracts/</code></td><td>New — OpenAPI + AsyncAPI</td></tr><tr><td>CI/CD</td><td><code>.github/workflows/</code></td><td>New — voice image and release workflows</td></tr><tr><td>Docs</td><td><code>docs/ard/VOICE-SYSTEM.md</code>, <code>docs/ard/VOICE-HLD.md</code></td><td>New/updated architecture docs</td></tr></tbody></table><h2 id="framework-alignment" tabindex="-1">Framework Alignment <a class="header-anchor" href="#framework-alignment" aria-label="Permalink to &quot;Framework Alignment&quot;">​</a></h2><p>This feature implements the voice slice of the ARC enterprise framework:</p><ul><li>It realizes the framework&#39;s <strong>sync flow for chat / voice</strong>.</li><li>It preserves the <strong>REST + async topic</strong> contract model.</li><li>It keeps <strong><code>arc-reasoner</code> as the only reasoning brain</strong>.</li><li>It lets teams run voice as a <strong>sidecar</strong> against existing infrastructure or as part of the full <code>reason</code> profile.</li></ul><h2 id="user-stories" tabindex="-1">User Stories <a class="header-anchor" href="#user-stories" aria-label="Permalink to &quot;User Stories&quot;">​</a></h2><h3 id="story-1-—-rest-speech-apis" tabindex="-1">Story 1 — REST speech APIs <a class="header-anchor" href="#story-1-—-rest-speech-apis" aria-label="Permalink to &quot;Story 1 — REST speech APIs&quot;">​</a></h3><p>As an application developer, I want OpenAI-compatible STT and TTS endpoints so that existing clients can add speech support without custom adapters.</p><p><strong>Acceptance Criteria</strong></p><ul><li><code>POST /v1/audio/transcriptions</code> accepts multipart audio and returns transcript text with language and duration metadata.</li><li><code>POST /v1/audio/speech</code> accepts JSON text input and returns a WAV stream with duration and sample-rate headers.</li><li>Default providers are local-first and work without external accounts.</li><li>Invalid files, unsupported formats, and provider failures return typed error responses.</li></ul><h3 id="story-2-—-realtime-voice-agent" tabindex="-1">Story 2 — Realtime voice agent <a class="header-anchor" href="#story-2-—-realtime-voice-agent" aria-label="Permalink to &quot;Story 2 — Realtime voice agent&quot;">​</a></h3><p>As an end user, I want to talk to ARC in a realtime room so that I can have low-latency spoken conversations with the same reasoning system used for chat.</p><p><strong>Acceptance Criteria</strong></p><ul><li><code>arc-voice-agent</code> joins <code>arc-realtime</code> rooms as a worker and processes turns with VAD → STT → <code>arc-reasoner</code> → TTS.</li><li><code>arc-voice-agent</code> uses <code>arc-reasoner</code> for reasoning and does not embed an independent LLM path.</li><li>End-to-end turn latency target remains within the documented budget of roughly 750–1550 ms.</li><li>Room-level failures publish a durable failure event and are visible in logs and traces.</li></ul><h3 id="story-3-—-durable-platform-events" tabindex="-1">Story 3 — Durable platform events <a class="header-anchor" href="#story-3-—-durable-platform-events" aria-label="Permalink to &quot;Story 3 — Durable platform events&quot;">​</a></h3><p>As a platform operator, I want durable voice session and turn events so that analytics, billing, and compliance can subscribe without coupling to Scarlett internals.</p><p><strong>Acceptance Criteria</strong></p><ul><li><code>arc-voice-agent</code> publishes <code>arc.voice.session.started</code>, <code>arc.voice.session.ended</code>, <code>arc.voice.turn.completed</code>, and <code>arc.voice.turn.failed</code>.</li><li>Event schemas are documented in <code>contracts/asyncapi.yaml</code>.</li><li>Events include correlation identifiers, room/session metadata, duration/latency fields, and provider outcome data.</li><li>Event publishing failure does not break the low-latency room response path.</li></ul><h3 id="story-4-—-offline-first-deployment" tabindex="-1">Story 4 — Offline-first deployment <a class="header-anchor" href="#story-4-—-offline-first-deployment" aria-label="Permalink to &quot;Story 4 — Offline-first deployment&quot;">​</a></h3><p>As a platform team, I want voice to work locally with no external speech vendors so that ARC stays aligned with the local-first constitution.</p><p><strong>Acceptance Criteria</strong></p><ul><li>Default STT provider is <code>faster-whisper</code>.</li><li>Default TTS provider is <code>piper</code>.</li><li>Cloud providers are optional adapters behind interfaces.</li><li>The service boots in the <code>reason</code> profile with no required cloud credentials.</li></ul><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><h3 id="functional" tabindex="-1">Functional <a class="header-anchor" href="#functional" aria-label="Permalink to &quot;Functional&quot;">​</a></h3><ul><li>[ ] FR-1: Create <code>services/voice/</code> with <code>service.yaml</code>, <code>Dockerfile</code>, <code>pyproject.toml</code>, contracts, and <code>src/voice/</code> package.</li><li>[ ] FR-2: Implement <code>POST /v1/audio/transcriptions</code> with provider abstraction and OpenAI-compatible response shape. Authentication is delegated to Heimdall (arc-gateway); standalone deployments without Heimdall must enforce bearer token validation separately.</li><li>[ ] FR-3: Implement <code>POST /v1/audio/speech</code> with provider abstraction and WAV streaming response. Authentication is delegated to Heimdall (arc-gateway); standalone deployments without Heimdall must enforce bearer token validation separately.</li><li>[ ] FR-4: Implement <code>GET /health</code> and <code>GET /health/deep</code> for shallow and dependency-aware checks.</li><li>[ ] FR-5: Start a LiveKit worker inside <code>arc-voice-agent</code> and join <code>arc-realtime</code> rooms for audio-to-audio sessions.</li><li>[ ] FR-6: Bridge voice turns to <code>arc-reasoner</code> over a configurable <code>arc-messaging</code> subject; default to <code>reasoner.request</code>.</li><li>[ ] FR-7: Publish durable voice events on <code>arc-streaming</code> for session lifecycle and turn outcomes.</li><li>[ ] FR-8: Add <code>services/voice/contracts/openapi.yaml</code> and <code>services/voice/contracts/asyncapi.yaml</code>.</li><li>[ ] FR-9: Add <code>voice</code> to the <code>reason</code> profile in <code>services/profiles.yaml</code>.</li><li>[ ] FR-10: Add observability with OTEL metrics, traces, and structured logs.</li><li>[ ] FR-11: Add CI/release workflows for the voice image.</li><li>[ ] FR-12: Reuse existing realtime infrastructure in <code>services/realtime/</code>; do not introduce a second transport stack.</li></ul><h3 id="non-functional" tabindex="-1">Non-Functional <a class="header-anchor" href="#non-functional" aria-label="Permalink to &quot;Non-Functional&quot;">​</a></h3><ul><li>[ ] NFR-1: <code>arc-voice-agent</code> runs as a non-root container and follows the standard service packaging pattern.</li><li>[ ] NFR-2: Default deployment works without external speech vendor credentials.</li><li>[ ] NFR-3: <code>GET /health</code> responds when the process is alive; <code>GET /health/deep</code> checks <code>arc-realtime</code> and <code>arc-messaging</code> connectivity and reports degraded status clearly.</li><li>[ ] NFR-4: OTEL captures per-turn latency for STT, Sherlock bridge, TTS, and total pipeline time.</li><li>[ ] NFR-5: Session and turn events never contain secrets or raw full-audio payloads.</li><li>[ ] NFR-6: The public async contract uses <code>arc-streaming</code> topics even though internal speed-path requests use <code>arc-messaging</code>.</li><li>[ ] NFR-7: The service passes <code>ruff</code>, <code>mypy</code>, and <code>pytest</code> following the same Python standards as <code>arc-reasoner</code>.</li><li>[ ] NFR-8: Voice events are published to <code>arc-streaming</code> with a 7-day default Pulsar retention policy. Platform operators may configure longer retention for compliance or billing audit requirements.</li></ul><h2 id="key-entities" tabindex="-1">Key Entities <a class="header-anchor" href="#key-entities" aria-label="Permalink to &quot;Key Entities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Entity</th><th>Description</th></tr></thead><tbody><tr><td><code>VoiceSession</code></td><td>LiveKit room participation and lifecycle metadata</td></tr><tr><td><code>VoiceTurn</code></td><td>Single user utterance plus agent response metrics</td></tr><tr><td><code>STTPort</code></td><td>Protocol interface for transcription providers</td></tr><tr><td><code>TTSPort</code></td><td>Protocol interface for synthesis providers</td></tr><tr><td><code>LLMBridgePort</code></td><td>Protocol interface for <code>arc-voice-agent</code> ↔ <code>arc-reasoner</code> turn exchange</td></tr><tr><td><code>VoiceSessionStarted</code></td><td>Durable async event for room/session start</td></tr><tr><td><code>VoiceTurnCompleted</code></td><td>Durable async event for successful turn completion</td></tr></tbody></table><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Browser or mobile SDK implementation</li><li>New realtime transport infrastructure beyond the already implemented LiveKit stack</li><li>Training or fine-tuning speech models</li><li>Enterprise telephony connectors beyond the base room and REST capabilities</li><li>Replacing <code>arc-reasoner</code> with a separate voice-native reasoning engine</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Existing realtime transport in <code>services/realtime/</code></li><li><code>arc-reasoner</code> request/reply contracts in <code>services/reasoner/</code></li><li><code>arc-messaging</code> for low-latency internal turn exchange</li><li><code>arc-streaming</code> for durable async voice events</li><li><code>arc-cache</code> and <code>arc-storage</code> for optional session state and recording support</li><li>Architecture guidance in <code>docs/ard/ARC-ENTERPRISE-AI-FRAMEWORK.md</code></li></ul><h2 id="edge-cases" tabindex="-1">Edge Cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Expected Behavior</th></tr></thead><tbody><tr><td><code>arc-realtime</code> unavailable</td><td>REST APIs still boot; room mode reports degraded/unavailable</td></tr><tr><td><code>arc-messaging</code> unavailable</td><td><code>health/deep</code> fails; room turns fail fast with typed error and failure event</td></tr><tr><td><code>arc-cache</code> unavailable</td><td>Room mode continues without cached hot state</td></tr><tr><td><code>arc-storage</code> or <code>arc-realtime-egress</code> unavailable</td><td>Sessions continue; recording/export features degrade gracefully</td></tr><tr><td>Local speech model cold start</td><td>First request is slower, but service remains healthy and emits latency metrics</td></tr><tr><td>Subject naming migration to <code>arc.reasoner.request</code></td><td><code>arc-voice-agent</code> changes by config, not by code rewrite</td></tr></tbody></table><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li>[ ] SC-1: <code>services/voice/</code> boots successfully in the <code>reason</code> profile.</li><li>[ ] SC-2: <code>POST /v1/audio/transcriptions</code> returns valid transcript metadata for supported audio formats.</li><li>[ ] SC-3: <code>POST /v1/audio/speech</code> streams playable WAV audio.</li><li>[ ] SC-4: <code>arc-voice-agent</code> joins an <code>arc-realtime</code> room and completes a full spoken turn through <code>arc-reasoner</code>.</li><li>[ ] SC-5: Voice session and turn events are emitted on <code>arc-streaming</code> with valid schema payloads.</li><li>[ ] SC-6: OTEL traces show STT, <code>arc-reasoner</code> bridge, and TTS spans per turn.</li><li>[ ] SC-7: Default local providers work without cloud credentials.</li></ul><h2 id="docs-links-update" tabindex="-1">Docs &amp; Links Update <a class="header-anchor" href="#docs-links-update" aria-label="Permalink to &quot;Docs &amp; Links Update&quot;">​</a></h2><ul><li>[ ] Create <code>docs/ard/VOICE-SYSTEM.md</code></li><li>[ ] Update <code>docs/ard/VOICE-HLD.md</code></li><li>[ ] Link the voice docs back to <code>docs/ard/ARC-ENTERPRISE-AI-FRAMEWORK.md</code></li><li>[ ] Add a docs update task for service references and profile documentation</li></ul><h2 id="constitution-compliance" tabindex="-1">Constitution Compliance <a class="header-anchor" href="#constitution-compliance" aria-label="Permalink to &quot;Constitution Compliance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Principle</th><th>Applies</th><th>Status</th><th>Notes</th></tr></thead><tbody><tr><td>I. Zero-Dep CLI</td><td>[ ]</td><td>n/a</td><td>No CLI runtime change</td></tr><tr><td>II. Platform-in-a-Box</td><td>[x]</td><td>WARNING</td><td>Voice is intentionally <code>reason</code> profile only because model footprint is too heavy for <code>think</code></td></tr><tr><td>III. Modular Services</td><td>[x]</td><td>PASS</td><td><code>services/voice/</code> is self-contained and depends on existing platform services</td></tr><tr><td>IV. Two-Brain</td><td>[x]</td><td>PASS</td><td>Python owns speech intelligence; Go infra remains unchanged</td></tr><tr><td>V. Polyglot Standards</td><td>[x]</td><td>PASS</td><td>FastAPI + ruff + mypy + pytest</td></tr><tr><td>VI. Local-First</td><td>[x]</td><td>PASS</td><td>Whisper + Piper are default providers</td></tr><tr><td>VII. Observability</td><td>[x]</td><td>PASS</td><td>OTEL metrics, traces, and health endpoints are required</td></tr><tr><td>VIII. Security</td><td>[x]</td><td>PASS</td><td>Non-root container, no secrets in logs or events</td></tr><tr><td>IX. Declarative</td><td>[x]</td><td>PASS</td><td>Contracts and service metadata are explicit</td></tr><tr><td>X. Stateful Ops</td><td>[x]</td><td>PASS</td><td>Session state and lifecycle events are queryable through platform dependencies</td></tr><tr><td>XI. Resilience</td><td>[x]</td><td>PASS</td><td>Graceful degradation for storage/cache and failure events for runtime issues</td></tr><tr><td>XII. Interactive</td><td>[ ]</td><td>n/a</td><td>No TUI scope</td></tr></tbody></table>',45)])])}const m=t(d,[["render",i]]);export{h as __pageData,m as default};
